# =============================================================================

import sys
from pathlib import Path
import pandas as pd
import numpy as np
from typing import Dict, List, Tuple, Any
import traceback

# Add project root to path for imports
PROJECT_ROOT = Path(__file__).resolve().parents[4]
sys.path.insert(0, str(PROJECT_ROOT))

# Import validation tools
from tools.validation import validate_numeric_range

# =============================================================================
# Configuration
# =============================================================================

RQ_DIR = Path(__file__).resolve().parents[1]  # results/ch7/7.5.4
LOG_FILE = RQ_DIR / "logs" / "step03_extract_vr_performance_scores.log"

# =============================================================================
# Logging Function
# =============================================================================

def log(msg):
    """Write to both log file and console."""
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
        f.flush()
    print(msg, flush=True)

# =============================================================================
# Main Analysis
# =============================================================================

if __name__ == "__main__":
    try:
        log("[START] Step 03: extract_vr_performance_scores")

        # =========================================================================
        # STEP 1: Load dfvr.csv Data
        # =========================================================================
        # Expected: Complete VR test data with task performance
        # Purpose: Extract episodic memory scores as outcome variable

        log("[LOAD] Loading dfvr.csv data...")
        dfvr_path = PROJECT_ROOT / "data" / "dfvr.csv"
        
        if not dfvr_path.exists():
            log(f"[ERROR] dfvr.csv not found at {dfvr_path}")
            sys.exit(1)
            
        dfvr_df = pd.read_csv(dfvr_path)
        log(f"[LOADED] dfvr.csv ({len(dfvr_df)} rows, {len(dfvr_df.columns)} cols)")

        # =========================================================================
        # STEP 2: Extract Episodic Memory Items
        # =========================================================================
        # Direct pandas operation: select RFR-N items (What domain)
        # What it does: Extract object memory items for clean episodic measure
        # Expected output: Per-item accuracy scores

        log("[ANALYSIS] Extracting episodic memory items...")
        
        # Define RFR-N What domain items (spatial object memory)
        memory_items = [
            "TQ_RFR-N-OBJ1", "TQ_RFR-N-OBJ2", "TQ_RFR-N-OBJ3", "TQ_RFR-N-OBJ4",
            "TQ_RFR-N-STRA", "TQ_RFR-N-PORT", "TQ_RFR-N-LAND"
        ]
        
        # Check which items are available in the data
        available_items = [item for item in memory_items if item in dfvr_df.columns]
        missing_items = [item for item in memory_items if item not in dfvr_df.columns]
        
        log(f"[ITEMS] Available memory items: {len(available_items)}")
        log(f"[ITEMS] Available: {available_items}")
        
        if missing_items:
            log(f"[WARNING] Missing items: {missing_items}")
            
        if len(available_items) < 3:
            log(f"[ERROR] Insufficient memory items available ({len(available_items)} < 3)")
            sys.exit(1)
        
        # Extract participant info and memory items
        id_cols = ["UID", "TEST"]
        memory_data = dfvr_df[id_cols + available_items].copy()
        
        # Convert to numeric (handle any string values)
        for item in available_items:
            memory_data[item] = pd.to_numeric(memory_data[item], errors='coerce')
        
        log(f"[EXTRACTED] Memory data for {len(memory_data)} observations")

        # =========================================================================
        # STEP 3: Compute Memory Scores
        # =========================================================================
        # Direct pandas operation: compute mean accuracy per test session
        # What it does: Aggregate item scores to test-level memory performance
        # Expected output: Memory_Score per UID × TEST

        log("[ANALYSIS] Computing memory scores...")
        
        # Compute mean accuracy across available items
        memory_data['Memory_Score'] = memory_data[available_items].mean(axis=1, skipna=True)
        
        # Count valid items per observation
        memory_data['N_Items'] = memory_data[available_items].count(axis=1)
        
        # Create output dataset
        memory_scores = memory_data[['UID', 'TEST', 'Memory_Score', 'N_Items']].copy()
        
        # Remove observations with insufficient data
        min_items = max(1, len(available_items) // 2)  # At least half of items required
        memory_scores = memory_scores[memory_scores['N_Items'] >= min_items]
        
        log(f"[COMPUTED] Memory scores for {len(memory_scores)} observations")
        log(f"[SCORES] Memory_Score range: {memory_scores['Memory_Score'].min():.3f} - {memory_scores['Memory_Score'].max():.3f}")
        log(f"[SCORES] Mean Memory_Score: {memory_scores['Memory_Score'].mean():.3f}")
        log(f"[SCORES] Items per observation: {memory_scores['N_Items'].value_counts().to_dict()}")

        # Check for missing data
        missing_scores = memory_scores['Memory_Score'].isna().sum()
        log(f"[MISSING] Missing memory scores: {missing_scores}/{len(memory_scores)} ({missing_scores/len(memory_scores):.1%})")

        log("[DONE] Memory score computation complete")

        # =========================================================================
        # STEP 4: Save Memory Scores
        # =========================================================================
        # Output: Test-level memory performance for multilevel analysis

        log("[SAVE] Saving memory scores...")
        
        # Final output (drop N_Items column for clean output)
        memory_output = memory_scores[['UID', 'TEST', 'Memory_Score']].copy()
        
        memory_output_path = RQ_DIR / "data" / "step03_memory_scores.csv"
        memory_output.to_csv(memory_output_path, index=False, encoding='utf-8')
        log(f"[SAVED] {memory_output_path} ({len(memory_output)} rows, {len(memory_output.columns)} cols)")

        # =========================================================================
        # STEP 5: Run Score Range Validation
        # =========================================================================
        # Tool: validate_numeric_range
        # Validates: Memory scores in expected [0, 1] range

        log("[VALIDATION] Running memory score validation...")
        
        # Validate memory score range
        memory_scores_clean = memory_output['Memory_Score'].dropna()
        range_validation = validate_numeric_range(
            data=memory_scores_clean.values,
            min_val=0.0,
            max_val=1.0,
            column_name="Memory_Score"
        )

        # Additional validation: Check distribution characteristics
        score_mean = memory_scores_clean.mean()
        score_std = memory_scores_clean.std()
        score_min = memory_scores_clean.min()
        score_max = memory_scores_clean.max()
        
        # Check for reasonable distribution (not all 0s or 1s)
        distribution_reasonable = (
            score_std > 0.05 and  # Some variability
            score_mean > 0.1 and score_mean < 0.9 and  # Not at floor/ceiling
            (score_max - score_min) > 0.1  # Reasonable range
        )

        log(f"[DISTRIBUTION] Mean: {score_mean:.3f}, SD: {score_std:.3f}")
        log(f"[DISTRIBUTION] Min: {score_min:.3f}, Max: {score_max:.3f}")
        log(f"[DISTRIBUTION] Distribution reasonable: {distribution_reasonable}")

        # Report validation results
        if range_validation.get('valid', False):
            log("[VALIDATION] Memory score range: PASS")
        else:
            log(f"[VALIDATION] Memory score range: FAIL - {range_validation.get('message', 'Unknown error')}")
            log(f"[VALIDATION] Out of range count: {range_validation.get('out_of_range_count', 0)}")
            
        if distribution_reasonable:
            log("[VALIDATION] Score distribution: PASS")
        else:
            log("[VALIDATION] Score distribution: WARNING - check for floor/ceiling effects")

        # Scientific Mantra logging between steps
        log("")
        log("=== SCIENTIFIC MANTRA ===")
        log("1. What question did we ask?")
        log("   -> Can we extract episodic memory scores as outcome for sleep analysis?")
        log("2. What did we find?")
        log(f"   -> {len(memory_output)} observations, mean score: {score_mean:.3f}")
        log(f"   -> Score range valid: {range_validation.get('valid', False)}, distribution reasonable: {distribution_reasonable}")
        log("3. What does it mean?")
        log("   -> We have clean memory outcome measure for within-person sleep effects")
        log("4. What should we do next?")
        log("   -> Proceed to step04: merge sleep and memory data")
        log("=========================")
        log("")

        log("[SUCCESS] Step 03 complete")
        sys.exit(0)

    except Exception as e:
        log(f"[ERROR] {str(e)}")
        log("[TRACEBACK] Full error details:")
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)